import 'dart:math'; class RetryPolicy { final int maxAttempts; final Duration baseDelay; final bool exponentialBackoff; const RetryPolicy({this.maxAttempts = 3, this.baseDelay = const Duration(seconds: 1), this.exponentialBackoff = true}); Duration delayFor(int attempt) { if (!exponentialBackoff) return baseDelay; return Duration(milliseconds: (baseDelay.inMilliseconds * pow(2, attempt)).toInt()); } bool shouldRetry(int attempt) => attempt < maxAttempts; }